     1→"use client";
     2→
     3→import dynamic from "next/dynamic";
     4→import { useState } from "react";
     5→
     6→import { useBuybackAsset } from "@/shared/api/query-hooks/use-buyback";
     7→import { useWalletInfo } from "@/shared/api/query-hooks/use-wallet";
     8→import type { BuybackDetailResponse } from "@/shared/api/services/buyback";
     9→import {
    10→  centsToDollars,
    11→  formatCentsToUSD,
    12→} from "@/shared/lib/utils/price-formatter";
    13→import { AssetHandoverOption } from "@/shared/types/asset.types";
    14→import { Button } from "@/shared/ui/button";
    15→import {
    16→  Dialog,
    17→  DialogCloseButton,
    18→  DialogContent,
    19→  DialogTitle,
    20→} from "@/shared/ui/dialog";
    21→import { toast } from "@/shared/ui/notification";
    22→import { PaymentMethodSelector } from "@/widgets/payment-method-selector";
    23→
    24→const DepositFundsModal = dynamic(
    25→  () =>
    26→    import("@/widgets/deposit-funds-modal").then((mod) => ({
    27→      default: mod.DepositFundsModal,
    28→    })),
    29→  { ssr: false },
    30→);
    31→
    32→interface BuybackPaymentModalProps {
    33→  isOpen: boolean;
    34→  onClose: () => void;
    35→  buyback: BuybackDetailResponse;
    36→}
    37→
    38→export function BuybackPaymentModal({
    39→  isOpen,
    40→  onClose,
    41→  buyback,
    42→}: BuybackPaymentModalProps) {
    43→  const buybackAsset = useBuybackAsset();
    44→  const { data: walletInfo } = useWalletInfo();
    45→  const [isDepositModalOpen, setIsDepositModalOpen] = useState(false);
    46→  useState(false);
    47→
    48→  const outstandingAmountCents =
    49→    buyback.computedDetails?.outstandingAmountCents || 0;
    50→
    51→  const currentBalanceCents = walletInfo?.balance || 0;
    52→  const hasSufficientBalance = currentBalanceCents >= outstandingAmountCents;
    53→  const shortfallCents = outstandingAmountCents - currentBalanceCents;
    54→
    55→  const handleSubmit = async () => {
    56→    if (!hasSufficientBalance) {
    57→      return;
    58→    }
    59→
    60→    try {
    61→      await buybackAsset.mutateAsync({
    62→        buybackId: buyback.id,
    63→        assetHandoverOption: AssetHandoverOption.Courier,
    64→      });
    65→
    66→      toast.success("Payment Successful!", {
    67→        description: "Payment has been processed from your wallet",
    68→      });
    69→
    70→      onClose();
    71→    } catch (error: unknown) {
    72→      const err = error as {
    73→        response?: {
    74→          data?: {
    75→            error?: string;
    76→            message?: string;
    77→          };
    78→        };
    79→      };
    80→
    81→      toast.error("Payment Failed", {
    82→        description:
    83→          err.response?.data?.message ||
    84→          "Unable to process payment. Please try again.",
    85→      });
    86→    }
    87→  };
    88→
    89→  const handleSelectTopUp = () => {
    90→    setIsDepositModalOpen(true);
    91→  };
    92→
    93→  return (
    94→    <Dialog open={isOpen} onOpenChange={onClose}>
    95→      <DialogContent className="w-[514px] gap-[40px] p-[30px]">
    96→        <div className="flex flex-col gap-[20px]">
    97→          <div className="flex items-center justify-between">
    98→            <DialogTitle className="font-medium font-sans text-[#2B3144] text-[23px] leading-[1.217em]">
    99→              Complete Buyback Payment
   100→            </DialogTitle>
   101→            <DialogCloseButton />
   102→          </div>
   103→
   104→          <div className="flex flex-col gap-[20px]">
   105→            <h3 className="font-bold font-serif text-base leading-[1.199em]">
   106→              Payment Details
   107→            </h3>
   108→
   109→            <div className="flex flex-col gap-[10px]">
   110→              <div className="flex items-center gap-[6px]">
   111→                <span className="font-serif text-sm leading-[1.199em]">
   112→                  Current Balance:
   113→                </span>
   114→                <span className="ml-auto font-bold font-serif text-sm leading-[1.199em]">
   115→                  {formatCentsToUSD(currentBalanceCents)}
   116→                </span>
   117→              </div>
   118→
   119→              <div className="flex items-center gap-[6px]">
   120→                <span className="font-bold font-serif text-sm leading-[1.199em]">
   121→                  Amount to Pay:
   122→                </span>
   123→                <span className="ml-auto font-bold font-serif text-lg leading-[1.199em]">
   124→                  {formatCentsToUSD(outstandingAmountCents)}
   125→                </span>
   126→              </div>
   127→
   128→              {!hasSufficientBalance && (
   129→                <div className="mt-2 rounded-[10px] border border-destructive/20 bg-destructive/5 p-3">
   130→                  <p className="font-bold font-sans text-destructive text-sm">
   131→                    Insufficient Balance
   132→                  </p>
   133→                  <p className="font-sans text-destructive/80 text-xs leading-[1.4em]">
   134→                    You need {formatCentsToUSD(shortfallCents)} more in your
   135→                    wallet to complete this payment.
   136→                  </p>
   137→                </div>
   138→              )}
   139→
   140→              {hasSufficientBalance && (
   141→                <p className="font-sans text-[#6C7080] text-xs leading-[1.4em]">
   142→                  This amount will be deducted from your wallet balance. After
   143→                  payment, you can arrange the asset return separately.
   144→                </p>
   145→              )}
   146→            </div>
   147→          </div>
   148→
   149→          {hasSufficientBalance ? (
   150→            <Button
   151→              type="button"
   152→              onClick={handleSubmit}
   153→              loading={buybackAsset.isPending}
   154→              disabled={buybackAsset.isPending}
   155→              className="h-[60px] w-full rounded-[10px] font-medium font-sans text-lg"
   156→            >
   157→              Pay Now
   158→            </Button>
   159→          ) : (
   160→            <PaymentMethodSelector
   161→              isOpen={true}
   162→              amount={outstandingAmountCents}
   163→              currentBalance={currentBalanceCents}
   164→              shortfall={shortfallCents}
   165→              onSelectTopUp={handleSelectTopUp}
   166→            />
   167→          )}
   168→        </div>
   169→      </DialogContent>
   170→
   171→      <DepositFundsModal
   172→        isOpen={isDepositModalOpen}
   173→        onClose={() => setIsDepositModalOpen(false)}
   174→        suggestedAmount={centsToDollars(shortfallCents)}
   175→      />
   176→    </Dialog>
   177→  );
   178→}
   179→

