     1→import { getErrorMessage } from "@/shared/types";
     2→import type { InsufficientBalanceError } from "@/shared/types/payment.types";
     3→import { toast } from "@/shared/ui/notification";
     4→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
     5→import type { AxiosError } from "axios";
     6→import { ApiKeys } from "../query-keys";
     7→import { buybackService } from "../services/buyback";
     8→import { useWalletBalance } from "./use-wallet";
     9→
    10→export interface BuybackPaymentError extends InsufficientBalanceError {
    11→  isInsufficientBalance: boolean;
    12→}
    13→
    14→export function useBuyback(id: string) {
    15→  return useQuery({
    16→    queryKey: ApiKeys.buybacks(id),
    17→    queryFn: () => buybackService.getDetails(id),
    18→    enabled: !!id,
    19→  });
    20→}
    21→
    22→export function useCompleteBuyback(
    23→  onInsufficientBalance?: (error: InsufficientBalanceError) => void,
    24→) {
    25→  const queryClient = useQueryClient();
    26→
    27→  return useMutation({
    28→    mutationFn: (buybackId: string) =>
    29→      buybackService.completeBuyback(buybackId),
    30→    onSuccess: (_, buybackId) => {
    31→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybacks(buybackId) });
    32→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybacks() });
    33→      queryClient.invalidateQueries({ queryKey: ApiKeys.wallet() });
    34→      queryClient.invalidateQueries({ queryKey: ApiKeys.walletTransactions() });
    35→      toast.success("Buyback completed successfully!");
    36→    },
    37→    onError: (error: AxiosError<InsufficientBalanceError>) => {
    38→      if (error?.response?.data?.error === "INSUFFICIENT_BALANCE") {
    39→        const insufficientBalanceError = error.response
    40→          .data as InsufficientBalanceError;
    41→        if (onInsufficientBalance) {
    42→          onInsufficientBalance(insufficientBalanceError);
    43→        } else {
    44→          const { recommendedTopUp } = insufficientBalanceError.details;
    45→          toast.error(
    46→            `Insufficient balance. Recommended top-up: $${(
    47→              recommendedTopUp / 100
    48→            ).toFixed(2)} (includes fees)`,
    49→          );
    50→        }
    51→      } else {
    52→        toast.error(getErrorMessage(error, "Failed to complete buyback"));
    53→      }
    54→    },
    55→  });
    56→}
    57→
    58→export function useBuybackPaymentStatus(buybackId: string) {
    59→  const { data: buyback, isLoading: buybackLoading } = useBuyback(buybackId);
    60→  const { balance, isLoading: balanceLoading } = useWalletBalance();
    61→
    62→  const outstandingAmount =
    63→    buyback?.computedDetails?.outstandingAmountCents ?? 0;
    64→  const hasSufficientBalance = balance >= outstandingAmount;
    65→  const shortfall = hasSufficientBalance ? 0 : outstandingAmount - balance;
    66→
    67→  return {
    68→    buyback,
    69→    outstandingAmount,
    70→    outstandingAmountDollars: outstandingAmount / 100,
    71→    currentBalance: balance,
    72→    currentBalanceDollars: balance / 100,
    73→    hasSufficientBalance,
    74→    shortfall,
    75→    shortfallDollars: shortfall / 100,
    76→    isLoading: buybackLoading || balanceLoading,
    77→  };
    78→}
    79→
    80→export function useRenewBuyback() {
    81→  const queryClient = useQueryClient();
    82→
    83→  return useMutation({
    84→    mutationFn: ({
    85→      buybackId,
    86→      data,
    87→    }: {
    88→      buybackId: string;
    89→      data: { emailOtpId: string; phoneOtpId: string };
    90→    }) => buybackService.renewBuyback(buybackId, data),
    91→    onSuccess: (_, { buybackId }) => {
    92→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybacks(buybackId) });
    93→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybacks() });
    94→      queryClient.invalidateQueries({ queryKey: ApiKeys.wallet() });
    95→      toast.success("Buyback renewed successfully!");
    96→    },
    97→    onError: (error: AxiosError<InsufficientBalanceError>) => {
    98→      if (error?.response?.data?.error === "INSUFFICIENT_BALANCE") {
    99→        const { details } = error.response.data as InsufficientBalanceError;
   100→        toast.error(
   101→          `Insufficient balance for extension fee. Recommended top-up: $${(
   102→            details.recommendedTopUp / 100
   103→          ).toFixed(2)} (includes fees)`,
   104→        );
   105→      } else {
   106→        toast.error(getErrorMessage(error, "Failed to renew buyback"));
   107→      }
   108→    },
   109→  });
   110→}
