   339→function WalletPageContent() {
   340→  const router = useRouter();
   341→  const searchParams = useSearchParams();
   342→  const { data: walletInfo, isLoading, error, refetch } = useWalletInfo();
   343→  const { data: paypalMethods } = usePayPalMethods();
   344→  const deletePaymentMethod = useDeletePaymentMethod();
   345→  const deletePayPalMethod = useDeletePayPalMethod();
   346→  const deleteCryptoAddress = useDeleteCryptoAddress();
   347→  const updatePaymentMethod = useUpdateStripeMethod();
   348→  const updatePayPalMethod = useUpdatePayPalMethod();
   349→  const updateCryptoAddress = useUpdateCryptoAddress();
   350→
   351→  useEffect(() => {
   352→    const success = searchParams.get("success");
   353→    const warning = searchParams.get("warning");
   354→    const canceled = searchParams.get("canceled");
   355→
   356→    if (success === "paypal_connected") {
   357→      toast.success("PayPal account connected successfully");
   358→      router.replace(APP_ROUTES.WALLET.ROOT);
   359→    } else if (warning === "paypal_duplicate") {
   360→      toast.warning("This PayPal account is already connected to your wallet");
   361→      router.replace(APP_ROUTES.WALLET.ROOT);
   362→    } else if (canceled === "paypal") {
   363→      toast.info("PayPal connection was canceled");
   364→      router.replace(APP_ROUTES.WALLET.ROOT);
   365→    }
   366→  }, [searchParams, router]);
   367→
   368→  const [isAddBankModalOpen, setIsAddBankModalOpen] = useState(false);
   369→  const [isAddCardModalOpen, setIsAddCardModalOpen] = useState(false);
   370→  const [isAddPayPalModalOpen, setIsAddPayPalModalOpen] = useState(false);
   371→  const [isAddCryptoModalOpen, setIsAddCryptoModalOpen] = useState(false);
   372→  const [deleteConfirmation, setDeleteConfirmation] = useState<{
   373→    type: "payment" | "paypal" | "crypto";
   374→    id: string;
   375→    label: string;
   376→  } | null>(null);
   377→  const [editPaymentMethod, setEditPaymentMethod] = useState<{
   378→    id: string;
   379→    nickname: string;
   380→    isDefault: boolean;
   381→  } | null>(null);
   382→  const [editPayPalMethod, setEditPayPalMethod] = useState<{
   383→    id: string;
   384→    nickname: string;
   385→    isDefault: boolean;
   386→  } | null>(null);
   387→  const [editCryptoAddress, setEditCryptoAddress] = useState<{
   388→    id: string;
   389→    label: string;
   390→    isDefault: boolean;
   391→  } | null>(null);
   392→  const [isWithdrawCryptoModalOpen, setIsWithdrawCryptoModalOpen] =
   393→    useState(false);
   394→  const [isWithdrawBankModalOpen, setIsWithdrawBankModalOpen] = useState(false);
   395→  const [isDepositModalOpen, setIsDepositModalOpen] = useState(false);
   396→
   397→  function confirmDelete() {
   398→    if (!deleteConfirmation) return;
   399→
   400→    if (deleteConfirmation.type === "payment") {
   401→      deletePaymentMethod.mutate(deleteConfirmation.id);
   402→    } else if (deleteConfirmation.type === "paypal") {
   403→      deletePayPalMethod.mutate(deleteConfirmation.id);
   404→    } else {
   405→      deleteCryptoAddress.mutate(deleteConfirmation.id);
   406→    }
   407→
   408→    setDeleteConfirmation(null);
   409→  }
   410→
   411→  async function savePaymentMethodEdit() {
   412→    if (!editPaymentMethod) return;
   413→    await updatePaymentMethod.mutateAsync({
   414→      id: editPaymentMethod.id,
   415→      data: {
   416→        nickname: editPaymentMethod.nickname,
   417→        setAsDefault: editPaymentMethod.isDefault,
   418→      },
   419→    });
   420→    setEditPaymentMethod(null);
   421→  }
   422→
   423→  async function savePayPalMethodEdit() {
   424→    if (!editPayPalMethod) return;
   425→    await updatePayPalMethod.mutateAsync({
   426→      id: editPayPalMethod.id,
   427→      data: {
   428→        nickname: editPayPalMethod.nickname,
   429→        setAsDefault: editPayPalMethod.isDefault,
   430→      },
   431→    });
   432→    setEditPayPalMethod(null);
   433→  }
   434→
   435→  async function saveCryptoAddressEdit() {
   436→    if (!editCryptoAddress) return;
   437→    await updateCryptoAddress.mutateAsync({
   438→      id: editCryptoAddress.id,
   439→      data: {
   440→        label: editCryptoAddress.label,
   441→        setAsDefault: editCryptoAddress.isDefault,
   442→      },
   443→    });
   444→    setEditCryptoAddress(null);
   445→  }
   446→
   447→  if (isLoading) {
   448→    return (
   449→      <div className="flex h-[400px] items-center justify-center">
   450→        <Loader />
   451→      </div>
   452→    );
   453→  }
   454→
   455→  if (error) {
   456→    const errorMessage = getErrorMessage(error, error.message);
   457→    return (
   458→      <div className="flex h-[400px] items-center justify-center">
   459→        <div className="flex flex-col items-center gap-4 text-center">
   460→          <p className="font-new-sans text-[#44403C] text-base">
   461→            {errorMessage}
   462→          </p>
   463→          <Button
   464→            onClick={() => refetch()}
   465→            className="h-9 rounded-lg bg-[#021171] px-4 font-new-sans text-[#F5F3EF] text-sm"
   466→          >
   467→            Retry
   468→          </Button>
   469→        </div>
   470→      </div>
   471→    );
   472→  }
   473→
   474→  if (!walletInfo) {
   475→    return (
   476→      <div className="flex h-[400px] items-center justify-center">
   477→        <p className="font-new-sans text-[#44403C] text-base">
   478→          Failed to load wallet information
   479→        </p>
   480→      </div>
   481→    );
   482→  }
   483→
   484→  const bankAccounts = walletInfo.savedPaymentMethods.filter(
   485→    (m) => m.type === "bank",
   486→  );
   487→  const cards = walletInfo.savedPaymentMethods.filter((m) => m.type === "card");
   488→
   489→  return (
   490→    <div className="mx-auto flex w-full max-w-[1500px] flex-col items-center gap-10 px-4 py-16 sm:px-6 lg:px-20 lg:py-20">
   491→      {/* Page Header */}
   492→      <div className="flex w-full max-w-[463px] flex-col items-center gap-3 text-center">
   493→        <h1 className="font-extralight font-new-serif text-[#44403C] text-[30px] leading-[120%]">
   494→          Accounts & Wallets
   495→        </h1>
   496→        <p className="font-new-sans text-[#44403C] text-base leading-[150%]">
   497→          Manage your payment methods, and registered accounts or crypto wallets
   498→          to get paid.
   499→        </p>
   500→      </div>
   501→
   502→      {/* Section Cards */}
   503→      <div className="flex w-full max-w-[600px] flex-col gap-5">
   504→        {/* Bank Account */}
   505→        <SectionCard
   506→          title="Bank Account"
   507→          subtitle="Add bank accounts to receive payments."
   508→          onAddNew={() => setIsAddBankModalOpen(true)}
   509→        >
   510→          {bankAccounts.length > 0 ? (
   511→            <div className="flex flex-col gap-2">
   512→              {bankAccounts.map((method) => {
   513→                const accountLabel =
   514→                  method.nickname ||
   515→                  (method.brand
   516→                    ? `${method.brand.charAt(0).toUpperCase() + method.brand.slice(1)} Account`
   517→                    : "Bank Account");
   518→                return (
   519→                  <AccountRow
   520→                    key={method.id}
   521→                    icon={<Building2 className="h-5 w-5" />}
   522→                    name={accountLabel}
   523→                    value={`****${method.last4}`}
   524→                    onDelete={() =>
   525→                      setDeleteConfirmation({
   526→                        type: "payment",
   527→                        id: method.id,
   528→                        label: "bank account",
   529→                      })
   530→                    }
   531→                  />
   532→                );
   533→              })}
   534→            </div>
   535→          ) : (
   536→            <EmptyState
   537→              icon={<Building2 className="h-5 w-5" />}
   538→              text="No bank accounts added"
   539→            />
   540→          )}
   541→        </SectionCard>
   542→
   543→        {/* Crypto Wallets */}
   544→        <SectionCard
   545→          title="Crypto Wallets"
   546→          subtitle="Add up to 5 wallets to receive and make stablecoin payments."
   547→          onAddNew={() => setIsAddCryptoModalOpen(true)}
   548→        >
   549→          {walletInfo.savedCryptoAddresses.length > 0 ? (
   550→            <div className="flex flex-col gap-2">
   551→              {walletInfo.savedCryptoAddresses.map((address) => {
   552→                const network =
   553→                  CRYPTO_NETWORK_LABELS[address.network as CryptoNetwork] ||
   554→                  address.network;
   555→                const shortAddress = `0x${address.address.slice(2, 5)}...${address.address.slice(-5)}`;
   556→                return (
   557→                  <AccountRow
   558→                    key={address.id}
   559→                    icon={<CircleDollarSign className="h-5 w-5" />}
   560→                    name={address.label || network}
   561→                    value={shortAddress}
   562→                    onDelete={() =>
   563→                      setDeleteConfirmation({
   564→                        type: "crypto",
   565→                        id: address.id,
   566→                        label: "crypto address",
   567→                      })
   568→                    }
   569→                  />
   570→                );
   571→              })}
   572→            </div>
   573→          ) : (
   574→            <EmptyState
   575→              icon={<CircleDollarSign className="h-5 w-5" />}
   576→              text="No crypto wallets added"
   577→            />
   578→          )}
   579→        </SectionCard>
   580→
   581→        {/* Debit/Credit Cards */}
   582→        <SectionCard
   583→          title="Debit/Credit Cards"
   584→          onAddNew={() => setIsAddCardModalOpen(true)}
